use PDF::API2;
use Text::CSV;

# Ouvrir le fichier PDF
my $pdf = PDF::API2->open('mon_fichier.pdf');

# Lire les métadonnées du PDF
my $info = $pdf->info;

# Extraire la date et l'auteur
my $date = $info->get('ModDate');
my $author = $info->get('Author');

print "Date : $date\n";
print "Auteur : $author\n";

# Extraire les tableaux (c'est plus compliqué, nécessite de parser le contenu du PDF)
my $text = $pdf->text;

# Convertir le texte en CSV
my $csv = Text::CSV->new({ binary => 1, auto_diag => 2 });
my $output_file = 'output.csv';

open my $fh, '>', $output_file or die "Could not open file '$output_file' $!";

# Écrire les données dans un fichier CSV
$csv->print($fh, ['Ligne', 'Donnée']);
foreach my $line ($text->lines) {
    $csv->print($fh, $line);
}

close $fh;

print "Données extraites et enregistrées dans $output_file\n";
